const hours = $.input.hoursBack || 24;
const since = new Date(Date.now() - hours * 60 * 60 * 1000);
const y = since.getFullYear();
const m = String(since.getMonth() + 1).padStart(2, '0');
const d = String(since.getDate()).padStart(2, '0');
const afterDate = y + '/' + m + '/' + d;
const today = new Date();
const todayStr = today.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
return { afterDate, todayStr, hoursBack: hours };

const response = $.steps.fetchEmails.response;
const messages = response.messages || response.data || [];
let emailList = [];

if (Array.isArray(messages)) {
  messages.slice(0, 40).forEach((msg, i) => {
    const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
    const getHeader = (name) => { const h = headers.find(h => h.name && h.name.toLowerCase() === name.toLowerCase()); return h ? h.value : ''; };
    emailList.push({
      index: i + 1,
      from: getHeader('From') || msg.from || 'Unknown',
      to: getHeader('To') || msg.to || '',
      subject: getHeader('Subject') || msg.subject || '(no subject)',
      snippet: msg.snippet || msg.body || '',
      date: getHeader('Date') || msg.date || ''
    });
  });
}

let compiled = '';
emailList.forEach(e => {
  compiled += 'Email #' + e.index + ':\n';
  compiled += '  From: ' + e.from + '\n';
  compiled += '  Subject: ' + e.subject + '\n';
  compiled += '  Date: ' + e.date + '\n';
  compiled += '  Preview: ' + e.snippet.slice(0, 300) + '\n\n';
});

return { compiled, emailCount: emailList.length, emails: emailList };

const data = $.steps.compileEmails.output;
const today = $.steps.buildDateFilter.output.todayStr;

let prompt = 'You are an executive email assistant. Analyze the following ' + data.emailCount + ' emails and create a comprehensive daily digest.\n\n';
prompt += 'DATE: ' + today + '\n';
prompt += 'EMAILS:\n' + data.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Group emails by category (e.g., Action Required, FYI/Updates, Meetings, External)\n';
prompt += '- For each email, extract: sender, subject, key point (1 sentence), and any action needed\n';
prompt += '- Identify the top 3-5 most important/urgent items\n';
prompt += '- List all action items with owners\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "digestDate": "' + today + '",\n';
prompt += '  "totalEmails": ' + data.emailCount + ',\n';
prompt += '  "topPriority": ["urgent item 1", "urgent item 2"],\n';
prompt += '  "categories": [\n';
prompt += '    { "name": "Action Required", "emails": [{ "from": "sender", "subject": "subj", "summary": "one line", "action": "what to do" }] }\n';
prompt += '  ],\n';
prompt += '  "actionItems": [{ "owner": "who", "task": "what", "urgency": "high/medium/low" }],\n';
prompt += '  "overallSummary": "2-3 sentence overview of today inbox"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { digestDate: '', totalEmails: 0, topPriority: [], categories: [], actionItems: [], overallSummary: raw }; }

const ai = $.steps.parseAI.output;
const emailCount = $.steps.compileEmails.output.emailCount;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Daily Email Digest', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Date:*\n' + (ai.digestDate || new Date().toLocaleDateString()) },
  { type: 'mrkdwn', text: '*Emails Processed:*\n' + emailCount }
] });
blocks.push({ type: 'divider' });

const summary = (ai.overallSummary || 'No summary available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Overview:*\n' + summary } });

if (ai.topPriority && ai.topPriority.length > 0) {
  blocks.push({ type: 'divider' });
  let priorityText = '*Top Priority Items:*\n';
  ai.topPriority.forEach((item, i) => { priorityText += (i + 1) + '. ' + item + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: priorityText.slice(0, 1800) } });
}

if (ai.categories && ai.categories.length > 0) {
  blocks.push({ type: 'divider' });
  ai.categories.slice(0, 5).forEach(cat => {
    let catText = '*' + cat.name + ':*\n';
    (cat.emails || []).slice(0, 5).forEach(e => {
      catText += '  - *' + (e.subject || 'No subject') + '* from ' + (e.from || 'Unknown') + '\n';
      if (e.summary) catText += '    ' + e.summary + '\n';
      if (e.action) catText += '    _Action: ' + e.action + '_\n';
    });
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText.slice(0, 1800) } });
  });
}

if (ai.actionItems && ai.actionItems.length > 0) {
  blocks.push({ type: 'divider' });
  let actionText = '*Action Items:*\n';
  ai.actionItems.slice(0, 10).forEach((a, i) => {
    const urgency = a.urgency ? ' [' + a.urgency.toUpperCase() + ']' : '';
    actionText += (i + 1) + '. ' + a.task + urgency + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: actionText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail + Claude AI | One CLI' }] });

const fallbackText = 'Daily Email Digest: ' + emailCount + ' emails processed - ' + (ai.overallSummary || '').slice(0, 100);
return { blocks, fallbackText };
